+    // Recovery should be stepwise: MetadataOnly → LexicalOnly → EmbedDeferred → Full
+    let recovery_transitions: Vec<_> = trace
+        .degradation_trace
+        .iter()
+        .filter(|r| r.changed && r.trigger == DegradationTrigger::Recovery)
+        .collect();
