+        failed_oracles.is_empty(),
+        "Failed {}/{} oracles:\n{}",
+        failed_oracles.len(),
+        total_oracles,
+        failed_oracles.join("\n")
+    );
+
+    eprintln!(
+        "All {total_oracles} oracles passed across {} scenarios",
+        scenarios.len()
+    );
